#include <bits/stdc++.h>
using namespace std;
int n,dp[51][51];
int main(){
    memset(dp,127,sizeof(dp));
    string s;
    cin>>s;
    s=" "+s;
    n=s.size()-1;
    for(int i=1;i<=n;i++)dp[i][i]=1;
    for(int len=2;len<=n;len++){
        for(int l=1;l+len-1<=n;l++){
            int r=l+len-1;
            for(int k=l;k<r;k++)
                dp[l][r]=min(dp[l][r],dp[l][k]+dp[k+1][r]-(s[l]==s[r]));
        }
    }
    cout<<dp[1][n];
    return 0;
}
